// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract SimpleCrowdsale {
    address payable public wallet;
    uint256 public rate;
    uint256 public weiRaised;
    mapping(address => uint256) public tokensPurchased;

    event TokensPurchased(address indexed purchaser, address indexed beneficiary, uint256 value, uint256 amount);

    bool private locked;

    modifier noReentrancy() {
        require(!locked, "No reentrancy");
        locked = true;
        _;
        locked = false;
    }

    modifier onlyAuthorized() {
        require(authorizedAddresses[msg.sender], "Not authorized");
        _;
    }

    mapping(address => bool) private authorizedAddresses;

    constructor(address payable _wallet, uint256 _rate, address[] memory _authorizedAddresses) {
        require(_wallet != address(0), "Invalid wallet address");
        require(_rate > 0, "Invalid rate");

        wallet = _wallet;
        rate = _rate;

        for (uint256 i = 0; i < _authorizedAddresses.length; i++) {
            authorizedAddresses[_authorizedAddresses[i]] = true;
        }
    }

    function buyTokens(address beneficiary) public payable noReentrancy onlyAuthorized {
        require(beneficiary != address(0), "Invalid beneficiary address");

        uint256 weiAmount = msg.value;
        uint256 tokens = weiAmount * rate / 10**18;

        // Update state variables
        weiRaised += weiAmount;
        tokensPurchased[beneficiary] += tokens;

        // Transfer funds to wallet
        (bool sent,) = wallet.call{value: weiAmount}("");
        require(sent, "Failed to send Ether");
    }
}
```

### Explanation of Changes
1. **Removed Duplicate Declarations**: Removed the duplicate function declarations for `wallet()`, `rate()`, and `weiRaised()`.
2. **Reentrancy Guard**: Added the `noReentrancy` modifier to prevent reentrancy attacks.
3. **Access Control**: Added the `onlyAuthorized` modifier to restrict calls to authorized addresses.
4. **Correct Constructor Initialization**: Ensured the constructor initializes `wallet` and `rate` correctly and rejects zero values.
5. **Pre-calculated State Updates**: Pre-calculated the total tokens to be purchased before updating state variables to minimize SSTORE operations.
6. **Deprecated Transfer Replacement**: Replaced `transfer` with `call{value: <amount>}("")` for better security and future-proofing.

These changes ensure the contract is secure, functional, and gas-efficient while adhering to the specified constraints.

